code = """import json, pandas as pd
cases = pd.DataFrame(var_call_rmHsYujdB0mcDRJPPccS9Imv)
accts = pd.DataFrame(var_call_FIZ4XbEgi3hA9cAqfySr6PtK)
# normalize ids: strip, remove leading '#'
cases['account_norm'] = cases['accountid'].astype(str).str.strip().str.lstrip('#')
accts['account_norm'] = accts['Id'].astype(str).str.strip().str.lstrip('#')
# numeric
cases['avg_days'] = pd.to_numeric(cases['avg_days'], errors='coerce')
# join
m = cases.merge(accts[['account_norm','ShippingState']], on='account_norm', how='left')
# aggregate by state (weighted by number of cases)
m['n_cases'] = pd.to_numeric(m.get('n_cases',1), errors='coerce').fillna(1)
# compute overall average closure time per state by weighting avg_days by n_cases
state = (m.dropna(subset=['ShippingState','avg_days'])
           .groupby('ShippingState')
           .apply(lambda g: (g['avg_days']*g['n_cases']).sum()/g['n_cases'].sum())
           .reset_index(name='avg_days'))
# pick min
best_state = state.sort_values('avg_days', ascending=True).iloc[0]['ShippingState'] if len(state)>0 else None
print('__RESULT__:')
print(json.dumps(best_state))"""

